from flask import Flask, request, jsonify
from functools import wraps

app = Flask(__name__)

# --- Mock Data and Authentication (for MVP purposes) ---

# Mock User Database
users_db = {
    "1": {"username": "alice", "email": "alice@example.com", "role": "user", "account_status": "active", "subscription_tier": "free"},
    "2": {"username": "bob", "email": "bob@example.com", "role": "moderator", "account_status": "active", "subscription_tier": "pro"},
    "3": {"username": "charlie", "email": "charlie@example.com", "role": "admin", "account_status": "active", "subscription_tier": "enterprise"},
    "4": {"username": "diana", "email": "diana@example.com", "role": "user", "account_status": "suspended", "subscription_tier": "free"},
}

# Mock current_user (would come from an authentication system)
# For this MVP, we hardcode an admin user
class MockUser:
    def __init__(self, user_id, role):
        self.id = user_id
        self.role = role

current_user = MockUser(user_id="3", role="admin") # Charlie is our current admin

# --- Helper Functions and Decorators ---

def admin_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if current_user.role != 'admin':
            return jsonify({"message": "Unauthorized: Admin privileges required"}), 403
        return f(*args, **kwargs)
    return decorated_function

# --- API Endpoint ---

@app.route("/api/users/<user_id>", methods=["PUT"])
@admin_required
def update_user(user_id):
    if user_id not in users_db:
        return jsonify({"message": "User not found"}), 404

    data = request.get_json()
    if not data:
        return jsonify({"message": "Request must contain JSON data"}), 400

    user = users_db[user_id]
    
    # Define allowed fields for update
    allowed_fields = [
        "email",
        "username",
        "role",
        "account_status",
        "subscription_tier",
    ]

    # Define allowed values for specific fields to prevent invalid data
    allowed_roles = ["user", "moderator", "admin"]
    allowed_account_statuses = ["active", "suspended"]
    allowed_subscription_tiers = ["free", "pro", "enterprise"]

    updated_fields = {}
    for field, value in data.items():
        if field in allowed_fields:
            if field == "role" and value not in allowed_roles:
                return jsonify({"message": f"Invalid role: {value}. Allowed roles are {', '.join(allowed_roles)}"}), 400
            elif field == "account_status" and value not in allowed_account_statuses:
                return jsonify({"message": f"Invalid account_status: {value}. Allowed statuses are {', '.join(allowed_account_statuses)}"}), 400
            elif field == "subscription_tier" and value not in allowed_subscription_tiers:
                return jsonify({"message": f"Invalid subscription_tier: {value}. Allowed tiers are {', '.join(allowed_subscription_tiers)}"}), 400
            
            # Prevent admin from changing their own role/status via this endpoint (optional security)
            # This is a good practice to prevent an admin from accidentally locking themselves out
            if user_id == current_user.id:
                if field == "role" and value != user["role"]:
                    return jsonify({"message": "Admins cannot change their own role via this endpoint for security reasons."}), 403
                if field == "account_status" and value != user["account_status"]:
                    return jsonify({"message": "Admins cannot change their own account status via this endpoint for security reasons."}), 403

            user[field] = value
            updated_fields[field] = value
        else:
            return jsonify({"message": f"Field '{field}' is not allowed for update"}), 400

    if not updated_fields:
        return jsonify({"message": "No valid fields provided for update"}), 400

    return jsonify({
        "message": "User updated successfully",
        "user_id": user_id,
        "updated_data": updated_fields,
        "current_user_state": user # Return the full updated user object
    }), 200

